import React from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Award, Microscope, Gem, CalendarCheck,
  CheckCircle2, Zap, ArrowRight, Star
} from 'lucide-react';

/* ─── Design tokens ───────────────────────────────────────── */
const T = {
  ivory:     '#F7F4EF',
  ivoryMid:  '#EAE5DA',
  gold:      '#B89A6A',
  goldLight: '#D4B98A',
  charcoal:  '#252422',
  ink:       '#47443E',
  muted:     '#8C897F',
  white:     '#FFFFFF',
  fontDisplay: '"Playfair Display", Georgia, serif',
  fontBody:    '"DM Sans", system-ui, sans-serif',
};

/* ─── Inject Google Fonts + keyframes once ────────────────── */
const injectGlobal = () => {
  if (document.getElementById('home-global')) return;
  const s = document.createElement('style');
  s.id = 'home-global';
  s.textContent = `
    @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;1,400&family=DM+Sans:wght@300;400;500&display=swap');
    @keyframes fadeUp {
      from { opacity:0; transform:translateY(24px); }
      to   { opacity:1; transform:translateY(0); }
    }
  `;
  document.head.appendChild(s);
};

/* ─── Component ───────────────────────────────────────────── */
const Home = () => {
  const navigate = useNavigate();
  injectGlobal();

  const [hBtn, setHBtn] = React.useState(null);
  const [hCard, setHCard] = React.useState(null);
  const [imgHover, setImgHover] = React.useState(false);

  const features = [
    { Icon: Award,         title: 'Expertise reconnue',    text: "Praticiens hautement qualifiés, plus de 20 ans d'expérience." },
    { Icon: Microscope,    title: 'Technologies avancées', text: "Équipements dernière génération pour diagnostics précis." },
    { Icon: Gem,           title: 'Service premium',       text: "Accompagnement personnalisé dans un cadre luxueux et raffiné." },
    { Icon: CalendarCheck, title: 'Horaires flexibles',    text: "Ouvert 6 jours sur 7, avec des plages horaires étendues." },
  ];

  /* ─ Styles ─ */
  const page = { fontFamily: T.fontBody, color: T.charcoal, background: T.ivory, overflowX: 'hidden' };

  /* hero */
  const heroSec = {
    display: 'grid', gridTemplateColumns: '1fr 1fr',
    alignItems: 'center', gap: '4rem',
    padding: '6rem 8vw 4rem', minHeight: '90vh',
  };
  const heroContent = {
    display: 'flex', flexDirection: 'column', gap: '2rem',
    animation: 'fadeUp .85s ease both',
  };
  const badgeStyle = {
    display: 'inline-flex', alignItems: 'center', gap: '6px',
    fontSize: '.7rem', fontWeight: 500, letterSpacing: '.14em',
    textTransform: 'uppercase', color: T.gold,
    border: `1px solid ${T.goldLight}`, borderRadius: '100px',
    padding: '.38rem 1.1rem', width: 'fit-content',
  };
  const h1Style = {
    fontFamily: T.fontDisplay, fontWeight: 400,
    fontSize: 'clamp(2.5rem,4.5vw,4.2rem)',
    lineHeight: 1.12, color: T.charcoal, letterSpacing: '-.01em',
  };
  const subtitleStyle = {
    fontSize: '.96rem', fontWeight: 300, color: T.ink,
    lineHeight: 1.82, maxWidth: '44ch',
  };
  const statsRow = {
    display: 'flex', alignItems: 'center',
    padding: '1.5rem 0',
    borderTop: `1px solid ${T.ivoryMid}`,
    borderBottom: `1px solid ${T.ivoryMid}`,
  };
  const statItem = (first) => ({
    display: 'flex', flexDirection: 'column', gap: '.25rem',
    padding: `0 ${first ? '1.8rem 0 0' : '1.8rem'}`,
  });
  const statNum = { fontFamily: T.fontDisplay, fontWeight: 400, fontSize: '1.9rem', color: T.charcoal, lineHeight: 1 };
  const statLbl = { fontSize: '.73rem', color: T.muted, letterSpacing: '.03em' };
  const divider = { width: '1px', height: '2.4rem', background: T.ivoryMid, flexShrink: 0 };

  const btnsRow = { display: 'flex', gap: '.9rem', flexWrap: 'wrap' };
  const btnBase = {
    display: 'inline-flex', alignItems: 'center', gap: '8px',
    fontFamily: T.fontBody, fontSize: '.85rem', fontWeight: 500,
    letterSpacing: '.03em', borderRadius: '100px',
    padding: '.85rem 2rem', cursor: 'pointer', border: 'none',
    transition: 'all .22s ease',
  };
  const btnPrimary = {
    ...btnBase,
    background: hBtn === 'p' ? T.gold : T.charcoal,
    color: T.ivory,
    transform: hBtn === 'p' ? 'translateY(-2px)' : 'none',
    boxShadow: hBtn === 'p' ? '0 8px 28px rgba(184,154,106,.38)' : 'none',
  };
  const btnOutline = {
    ...btnBase,
    background: hBtn === 'o' ? T.charcoal : 'transparent',
    color: hBtn === 'o' ? T.ivory : T.charcoal,
    border: `1px solid ${T.charcoal}`,
    transform: hBtn === 'o' ? 'translateY(-2px)' : 'none',
  };

  /* hero visual */
  const heroVisual = { position: 'relative', animation: 'fadeUp .85s .2s ease both', opacity: 0 };
  const imgFrame = {
    borderRadius: '24px', overflow: 'hidden', aspectRatio: '4/5',
    boxShadow: `0 0 0 1px ${T.ivory}, 0 0 0 2px ${T.goldLight}, 0 30px 80px rgba(37,36,34,.14)`,
  };
  const imgStyle = {
    width: '100%', height: '100%', objectFit: 'cover', display: 'block',
    transition: 'transform 7s ease',
    transform: imgHover ? 'scale(1.05)' : 'scale(1)',
  };
  const pillBase = {
    position: 'absolute', display: 'flex', alignItems: 'center',
    gap: '.65rem', background: T.white, border: `1px solid ${T.ivoryMid}`,
    borderRadius: '14px', padding: '.75rem 1.1rem',
    boxShadow: '0 12px 40px rgba(37,36,34,.1)',
  };
  const pillTitle = { fontSize: '.82rem', fontWeight: 500, color: T.charcoal, margin: 0, whiteSpace: 'nowrap' };
  const pillSub = { fontSize: '.72rem', color: T.muted, margin: '.1rem 0 0' };

  /* features */
  const featuresSec = { padding: '7rem 8vw', background: T.white };
  const secHeader = { textAlign: 'center', maxWidth: '560px', margin: '0 auto 4rem' };
  const eyebrow = { display: 'inline-block', fontSize: '.7rem', fontWeight: 500, letterSpacing: '.14em', textTransform: 'uppercase', color: T.gold, marginBottom: '.9rem' };
  const h2Style = { fontFamily: T.fontDisplay, fontWeight: 400, fontSize: 'clamp(1.9rem,3vw,2.7rem)', color: T.charcoal, lineHeight: 1.22, letterSpacing: '-.01em', marginBottom: '.85rem' };
  const secP = { fontSize: '.94rem', fontWeight: 300, color: T.ink, lineHeight: 1.78 };
  const cardGrid = { display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: '1.4rem' };

  const cardStyle = (i) => ({
    background: T.ivory,
    border: `1px solid ${hCard === i ? T.goldLight : T.ivoryMid}`,
    borderRadius: '16px', padding: '2rem 1.6rem',
    transform: hCard === i ? 'translateY(-6px)' : 'none',
    boxShadow: hCard === i ? '0 20px 50px rgba(37,36,34,.09)' : 'none',
    transition: 'all .28s ease',
    cursor: 'default',
    animation: `fadeUp .7s ${0.1 + i * 0.1}s ease both`,
    opacity: 0,
  });
  const iconWrap = { display: 'flex', alignItems: 'center', justifyContent: 'center', width: '48px', height: '48px', background: 'rgba(184,154,106,.12)', borderRadius: '12px', marginBottom: '1.25rem', color: T.gold };
  const h3Style = { fontFamily: T.fontDisplay, fontWeight: 400, fontSize: '1.2rem', color: T.charcoal, marginBottom: '.55rem' };
  const cardP = { fontSize: '.87rem', fontWeight: 300, color: T.ink, lineHeight: 1.72, margin: 0 };

  return (
    <div style={page}>

      {/* ── HERO ── */}
      <section style={heroSec}>
        <div style={heroContent}>

          <span style={badgeStyle}>
            <Star size={11} strokeWidth={2} />
            Excellence Certifiée
          </span>

          <h1 style={h1Style}>
            Votre <em style={{ fontStyle: 'italic', color: T.gold }}>sourire</em>,<br />
            notre passion
          </h1>

          <p style={subtitleStyle}>
            Des soins dentaires d'exception dans un environnement apaisant.
            Notre équipe vous garantit des résultats parfaits grâce aux
            technologies les plus avancées.
          </p>

          <div style={statsRow}>
            {[
              { n: '20+',  l: "Années d'expérience" },
              { n: '15 k+', l: 'Patients satisfaits' },
              { n: '98 %', l: 'Taux de satisfaction' },
            ].map(({ n, l }, i) => (
              <React.Fragment key={l}>
                {i > 0 && <div style={divider} />}
                <div style={statItem(i === 0)}>
                  <span style={statNum}>{n}</span>
                  <span style={statLbl}>{l}</span>
                </div>
              </React.Fragment>
            ))}
          </div>

          <div style={btnsRow}>
            <button
              style={btnPrimary}
              onMouseEnter={() => setHBtn('p')}
              onMouseLeave={() => setHBtn(null)}
              onClick={() => navigate('/services')}
            >
              Nos services <ArrowRight size={15} strokeWidth={2} />
            </button>
            <button
              style={btnOutline}
              onMouseEnter={() => setHBtn('o')}
              onMouseLeave={() => setHBtn(null)}
              onClick={() => navigate('/about')}
            >
              À propos
            </button>
          </div>
        </div>

        {/* Visual */}
        <div style={heroVisual}>
          <div
            style={imgFrame}
            onMouseEnter={() => setImgHover(true)}
            onMouseLeave={() => setImgHover(false)}
          >
            <img
              src="https://images.unsplash.com/photo-1606811841689-23dfddce3e95?w=900&h=700&fit=crop&q=90"
              alt="Cabinet dentaire moderne"
              style={imgStyle}
            />
          </div>

          <div style={{ ...pillBase, bottom: '9%', left: '-1.5rem', animation: 'fadeUp .8s .5s ease both', opacity: 0 }}>
            <CheckCircle2 size={22} strokeWidth={1.6} color={T.gold} />
            <div>
              <p style={pillTitle}>Équipe certifiée</p>
              <p style={pillSub}>Dentistes diplômés</p>
            </div>
          </div>

          <div style={{ ...pillBase, top: '10%', right: '-1.5rem', animation: 'fadeUp .8s .7s ease both', opacity: 0 }}>
            <Zap size={22} strokeWidth={1.6} color={T.gold} />
            <div>
              <p style={pillTitle}>Technologies avancées</p>
              <p style={pillSub}>Équipements de pointe</p>
            </div>
          </div>
        </div>
      </section>

      {/* ── FEATURES ── */}
      <section style={featuresSec}>
        <header style={secHeader}>
          <span style={eyebrow}>Pourquoi nous choisir</span>
          <h2 style={h2Style}>L'excellence à votre service</h2>
          <p style={secP}>
            Une approche complète alliant expertise médicale, technologies
            de pointe et accompagnement personnalisé.
          </p>
        </header>

        <div style={cardGrid}>
          {features.map(({ Icon, title, text }, i) => (
            <div
              key={title}
              style={cardStyle(i)}
              onMouseEnter={() => setHCard(i)}
              onMouseLeave={() => setHCard(null)}
            >
              <div style={iconWrap}>
                <Icon size={22} strokeWidth={1.6} />
              </div>
              <h3 style={h3Style}>{title}</h3>
              <p style={cardP}>{text}</p>
            </div>
          ))}
        </div>
      </section>

    </div>
  );
};

export default Home;
